+fn resolve_destination_root(workspace_root: &Path, destination: Option<&str>) -> PathBuf {
+    match destination {
+        Some(raw) => {
+            let expanded = expand_tilde(raw);
+            if expanded.is_absolute() {
+                expanded
+            } else {
+                workspace_root.join(expanded)
+            }
+        }
+        None => workspace_root.join(".wa").join("backups"),
+    }
+}
