+fn unique_backup_path(base_dir: &Path, base_name: &str) -> PathBuf {
+    let mut candidate = base_dir.join(base_name);
+    if !candidate.exists() {
+        return candidate;
+    }
+    for idx in 1..=1000 {
+        let name = format!("{base_name}_{idx:02}");
+        candidate = base_dir.join(name);
+        if !candidate.exists() {
+            return candidate;
+        }
+    }
+    candidate
+}
